function assumeUnusedAddress(address addr) internal view virtual {
    uint256 size;
    assembly {
        size := extcodesize(addr)
    }
    vm.assume(size == 0);

    assumeNotPrecompile(addr);
    assumeNotZeroAddress(addr);
    assumeNotForgeAddress(addr);
}

function setupDeposit(address account, uint256 assets) internal {
    vm.startPrank(account);
    fundsAsset.mint(account, assets);
    fundsAsset.approve(address(pool), assets);
    vm.stopPrank();

    setLenderAllowlist(address(poolManager), account, true);

    vm.prank(account);
    pool.deposit(assets, account);

    setLenderAllowlist(address(poolManager), account, false);
}

function testSetAuthorization(address addressFuzz) public {
    vm.assume(addressFuzz != address(this));

    morpho.setAuthorization(addressFuzz, true);

    assertTrue(morpho.isAuthorized(address(this), addressFuzz));

    morpho.setAuthorization(addressFuzz, false);

    assertFalse(morpho.isAuthorized(address(this), addressFuzz));
}

